use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::collections::HashMap;use std::marker::PhantomData;pub struct MorseDecoder;fn build_morse_map() -> HashMap<&'static str, &'static str> {    let mut m = HashMap::new();    m.insert(".-", "A"); m.insert("-...", "B"); m.insert("-.-.", "C"); m.insert("-..", "D");    m.insert(".", "E"); m.insert("..-.", "F"); m.insert("--.", "G"); m.insert("....", "H");    m.insert("..", "I"); m.insert(".---", "J"); m.insert("-.-", "K"); m.insert(".-..", "L");    m.insert("--", "M"); m.insert("-.", "N"); m.insert("---", "O"); m.insert(".--.", "P");    m.insert("--.-", "Q"); m.insert(".-.", "R"); m.insert("...", "S"); m.insert("-", "T");    m.insert("..-", "U"); m.insert("...-", "V"); m.insert(".--", "W"); m.insert("-..-", "X");    m.insert("-.--", "Y"); m.insert("--..", "Z");    m.insert(".----", "1"); m.insert("..---", "2"); m.insert("...--", "3"); m.insert("....-", "4");    m.insert(".....", "5"); m.insert("-....", "6"); m.insert("--...", "7"); m.insert("---..", "8");    m.insert("----.", "9"); m.insert("-----", "0");    m}impl Crack for Decoder<MorseDecoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let trimmed = text.trim();        if !trimmed.chars().all(|c| c == '.' || c == '-' || c == ' ' || c == '/' || c == '|') {            return result;        }        let morse_map = build_morse_map();        let separator = if trimmed.contains(" / ") { " / " } else if trimmed.contains(" | ") { " | " } else { " " };        let words: Vec<&str> = trimmed.split(separator).collect();        let mut decoded = String::new();        for word in &words {            let letters: Vec<&str> = word.split(' ').collect();            for letter in &letters {                if let Some(ch) = morse_map.get(letter) {                    decoded.push_str(ch);                } else if letter.is_empty() {                    continue;                } else {                    return result;                }            }            decoded.push(' ');        }        let decoded = decoded.trim().to_string();        if !decoded.is_empty() && check_string_success(&decoded, text) {            let check_result = checker.check_text(&decoded);            if check_result.is_identified {                result.success = true;                result.unencrypted_text = Some(vec![decoded]);                result.checker_name = check_result.checker_name;            }        }        result    }    fn get_name(&self) -> &'static str { "Morse" }    fn get_popularity(&self) -> f32 { 0.5 }    fn get_tags(&self) -> &'static [&'static str] { &["morse", "decoder", "cipher"] }    fn get_description(&self) -> &'static str { "Morse code is a method of encoding text characters as sequences of dots and dashes." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Morse_code" }}impl Decoder<MorseDecoder> {    pub fn new() -> Self {        Decoder {            name: "Morse",            description: "Morse code is a method of encoding text characters as sequences of dots and dashes.",            link: "https://en.wikipedia.org/wiki/Morse_code",            tags: vec!["morse", "decoder", "cipher"],            popularity: 0.5,            phantom: PhantomData,        }    }}



